# incident-channel-standards.yaml
channel:
  naming:
    format: "inc-YYYY-MM-DD-NNN"
    example: "inc-2026-07-14-003"
    counter: auto-incremented per calendar day
    prefix_for_sev1: "sev1-"  # e.g. sev1-inc-2026-07-14-003 for visibility

  pinned_messages:  # IC posts these at incident open
    - type: incident_summary
      format: |
        **INCIDENT OPEN**
        Severity: SEV-{N}
        Category: {capability|infra|safety|integration|security}
        Impact: {description}
        IC: @{ic_name}
        Tech Lead: @{tech_lead_name}
        Scribe: @{scribe_name}
        Bridge: {zoom_link}
        Runbook: {runbook_url}
        Jira: {jira_ticket_url}
        Status Page: {statuspage_url}
        Declared at: {ISO_timestamp}

  scribe_protocol:
    - post timestamped update for every action taken (format: [HH:MM UTC] action)
    - post outcome of every decision (format: [HH:MM UTC] DECISION: description)
    - post when severity changes (format: [HH:MM UTC] SEVERITY CHANGE: SEV-N → SEV-M)
    - post when key personnel join or leave the bridge
    - never delete or edit posts; append corrections as new messages

  retention:
    archive_after_days: 90
    export_to_incident_record: true
    legal_hold_for_sev1: true  # do not archive without Legal approval

  access:
    default: all engineering staff can join
    sev1_restriction: paged personnel + IC + scribe only in first 30 min
    external: no external parties in Slack channel; use email for vendor comms

"""war_room_access_audit.py -- quarterly access audit for war room tools."""
from __future__ import annotations
import os
import yaml
import httpx
from dataclasses import dataclass
from typing import Optional


@dataclass
class AccessGap:
    person_id: str
    tool: str
    required_level: str
    current_level: Optional[str]


REQUIRED_ACCESS = {
    "IC": {
        "grafana": "viewer",
        "jaeger": "viewer",
        "statuspage": "editor",
        "pagerduty": "manager",
        "slack_incident_bot": "user",
    },
    "technical_lead": {
        "grafana": "viewer",
        "jaeger": "viewer",
        "session_replay": "viewer",
        "pagerduty": "responder",
        "slack_incident_bot": "user",
    },
    "scribe": {
        "statuspage": "editor",
        "slack_incident_bot": "user",
        "confluence": "editor",
    },
}


def audit_access(
    roster_path: str = "ic-roster.yaml",
) -> list[AccessGap]:
    """Return list of access gaps for all IC roster members."""
    with open(roster_path) as f:
        roster = yaml.safe_load(f)["roster"]

    gaps = []
    for member in roster["members"]:
        role = "IC" if member["availability"] == "primary" else "technical_lead"
        required = REQUIRED_ACCESS.get(role, {})
        for tool, required_level in required.items():
            current = _get_tool_access(member["id"], tool)
            if current is None or not _meets_level(current, required_level):
                gaps.append(AccessGap(
                    person_id=member["id"],
                    tool=tool,
                    required_level=required_level,
                    current_level=current,
                ))
    return gaps


def _get_tool_access(person_id: str, tool: str) -> Optional[str]:
    """Query tool API for current access level. Returns None if no access."""
    # In production, replace with actual API calls per tool
    # This is a stub showing the pattern
    return None  # Stub: would call Grafana/PD/etc APIs


def _meets_level(current: str, required: str) -> bool:
    LEVELS = {"viewer": 1, "responder": 2, "user": 1, "editor": 2, "manager": 3}
    return LEVELS.get(current, 0) >= LEVELS.get(required, 0)


if __name__ == "__main__":
    gaps = audit_access()
    if not gaps:
        print("All war room access requirements met.")
    else:
        print(f"ACCESS GAPS FOUND ({len(gaps)}):")
        for gap in gaps:
            print(f"  {gap.person_id}: {gap.tool} needs {gap.required_level}, has {gap.current_level or 'none'}")
